import sys
from assist_constants import Dark, Light

def detect_os_theme() -> str:
    if sys.platform == 'win32':
        try:
            import winreg
            key = winreg.OpenKey(winreg.HKEY_CURRENT_USER, 'Software\\Microsoft\\Windows\\CurrentVersion\\Themes\\Personalize')
            val, _ = winreg.QueryValueEx(key, 'AppsUseLightTheme')
            winreg.CloseKey(key)
            return 'light' if val == 1 else 'dark'
        except Exception:
            pass
    return 'dark'

def resolve_theme(mode: str) -> str:
    if mode in ('system', 'auto'):
        return detect_os_theme()
    return 'light' if mode == 'light' else 'dark'

def _build_stylesheet(c) -> str:
    return f'\nQWidget {{\n    background-color: {c.PANEL};\n    color: {c.TEXT};\n    font-family: "Meiryo", "Yu Gothic UI", "Segoe UI", sans-serif;\n    font-size: 10pt;\n}}\nQMainWindow, QDialog {{\n    background-color: {c.BG};\n}}\nQLabel {{\n    background-color: transparent;\n    color: {c.TEXT};\n}}\nQPushButton {{\n    background-color: {c.SEP};\n    color: {c.TEXT};\n    border: none;\n    border-radius: 4px;\n    padding: 5px 10px;\n}}\nQPushButton:hover {{\n    background-color: {c.ACCENT};\n    color: white;\n}}\nQPushButton:disabled {{\n    background-color: {c.PANEL};\n    color: {c.TEXT_SUB};\n}}\nQLineEdit, QTextEdit, QPlainTextEdit {{\n    background-color: {c.SEP};\n    color: {c.TEXT};\n    border: 1px solid {c.SEP};\n    border-radius: 3px;\n    padding: 3px 5px;\n    selection-background-color: {c.ACCENT};\n}}\nQComboBox {{\n    background-color: {c.SEP};\n    color: {c.TEXT};\n    border: 1px solid {c.SEP};\n    border-radius: 3px;\n    padding: 3px 6px;\n}}\nQComboBox::drop-down {{ border: none; width: 18px; }}\nQComboBox QAbstractItemView {{\n    background-color: {c.PANEL};\n    color: {c.TEXT};\n    selection-background-color: {c.ACCENT};\n    selection-color: white;\n    border: 1px solid {c.SEP};\n}}\nQTabWidget::pane {{\n    border: 1px solid {c.SEP};\n    background: {c.BG};\n    top: -1px;\n}}\nQTabBar::tab {{\n    background: {c.SEP};\n    color: {c.TEXT_SUB};\n    padding: 6px 14px;\n    border: none;\n    border-top-left-radius: 4px;\n    border-top-right-radius: 4px;\n    margin-right: 2px;\n}}\nQTabBar::tab:selected {{\n    background: {c.ACCENT};\n    color: white;\n}}\nQTabBar::tab:hover:!selected {{\n    background: {c.HEADER};\n    color: {c.TEXT};\n}}\nQTableWidget, QTreeWidget {{\n    background-color: {c.ROW_ODD};\n    color: {c.TEXT};\n    gridline-color: {c.SEP};\n    border: 1px solid {c.SEP};\n    alternate-background-color: {c.ROW_EVEN};\n}}\nQTableWidget::item:selected, QTreeWidget::item:selected {{\n    background-color: {c.ACCENT};\n    color: white;\n}}\nQListWidget#manualNav {{\n    background-color: {c.PANEL};\n    color: {c.TEXT};\n    border: none;\n    border-right: 1px solid {c.SEP};\n    outline: none;\n}}\nQListWidget#manualNav::item {{\n    padding: 6px 10px;\n    border-bottom: 1px solid {c.SEP};\n}}\nQListWidget#manualNav::item:selected {{\n    background-color: {c.ACCENT};\n    color: white;\n}}\nQListWidget#manualNav::item:hover:!selected {{\n    background-color: {c.HEADER};\n}}\nQListWidget#saveList {{\n    background-color: {c.PANEL};\n    color: {c.TEXT};\n    border: 1px solid {c.SEP};\n    outline: none;\n}}\nQListWidget#saveList::item {{\n    padding: 5px 8px;\n    border-bottom: 1px solid {c.SEP};\n}}\nQListWidget#saveList::item:selected {{\n    background-color: {c.ACCENT};\n    color: white;\n}}\nQListWidget#saveList::item:hover:!selected {{\n    background-color: {c.HEADER};\n}}\nQListWidget#saveLeftList {{\n    background-color: {c.PANEL};\n    color: {c.TEXT};\n    border: none;\n    border-right: 1px solid {c.SEP};\n    outline: none;\n}}\nQListWidget#saveLeftList::item {{\n    padding: 5px 8px;\n    border-bottom: 1px solid {c.SEP};\n    font-size: 9pt;\n}}\nQListWidget#saveLeftList::item:selected {{\n    background-color: {c.ACCENT};\n    color: white;\n}}\nQListWidget#saveLeftList::item:hover:!selected {{\n    background-color: {c.HEADER};\n}}\nQPushButton#viewToggleBtn {{\n    background-color: {c.SEP};\n    color: {c.TEXT_SUB};\n    border: 1px solid {c.SEP};\n    border-radius: 3px;\n    padding: 4px 12px;\n}}\nQPushButton#viewToggleBtn:checked {{\n    background-color: {c.ACCENT};\n    color: white;\n    border-color: {c.ACCENT};\n}}\nQPushButton#viewToggleBtn:hover:!checked {{\n    background-color: {c.HEADER};\n    color: {c.TEXT};\n}}\nQLabel#detailHeader {{\n    font-size: 12pt;\n    font-weight: bold;\n    padding-bottom: 6px;\n    border-bottom: 2px solid {c.ACCENT};\n    color: {c.TEXT};\n}}\nQHeaderView::section {{\n    background-color: {c.HEADER};\n    color: {c.TEXT};\n    padding: 4px 6px;\n    border: none;\n    border-right: 1px solid {c.SEP};\n    font-weight: bold;\n}}\nQScrollBar:vertical {{\n    width: 8px;\n    background: {c.PANEL};\n    border-radius: 4px;\n}}\nQScrollBar::handle:vertical {{\n    background: {c.SEP};\n    border-radius: 4px;\n    min-height: 20px;\n}}\nQScrollBar::add-line:vertical, QScrollBar::sub-line:vertical {{ height: 0; }}\nQScrollBar:horizontal {{\n    height: 8px;\n    background: {c.PANEL};\n    border-radius: 4px;\n}}\nQScrollBar::handle:horizontal {{\n    background: {c.SEP};\n    border-radius: 4px;\n    min-width: 20px;\n}}\nQScrollBar::add-line:horizontal, QScrollBar::sub-line:horizontal {{ width: 0; }}\nQSplitter::handle {{ background: {c.SEP}; }}\nQStatusBar {{\n    background-color: {c.PANEL};\n    color: {c.TEXT_SUB};\n    font-size: 9pt;\n}}\nQMenuBar {{\n    background-color: {c.HEADER};\n    color: {c.TEXT};\n}}\nQMenuBar::item:selected {{ background-color: {c.ACCENT}; color: white; }}\nQMenu {{\n    background-color: {c.PANEL};\n    color: {c.TEXT};\n    border: 1px solid {c.SEP};\n}}\nQMenu::item:selected {{ background-color: {c.ACCENT}; color: white; }}\nQToolTip {{\n    background-color: {c.SEP};\n    color: {c.TEXT};\n    border: 1px solid {c.TEXT_SUB};\n    padding: 3px 5px;\n}}\nQTextBrowser {{\n    background-color: {c.BG};\n    color: {c.TEXT};\n    border: none;\n    font-size: 10pt;\n    line-height: 1.6;\n}}\nQPushButton#winCtrlBtn {{\n    background: transparent;\n    color: {c.TEXT_SUB};\n    border-radius: 3px;\n    padding: 0;\n    font-size: 11pt;\n}}\nQPushButton#winCtrlBtn:hover {{\n    background: {c.SEP};\n    color: {c.TEXT};\n}}\nQPushButton#winCloseBtn {{\n    background: transparent;\n    color: {c.TEXT_SUB};\n    border-radius: 3px;\n    padding: 0;\n    font-size: 11pt;\n}}\nQPushButton#winCloseBtn:hover {{\n    background: {c.ERROR};\n    color: white;\n}}\n'

def get_stylesheet(mode: str) -> str:
    effective = resolve_theme(mode)
    return _build_stylesheet(Light if effective == 'light' else Dark)
